import React, { useState, useEffect, useCallback } from 'react';
import CryptoJS from 'crypto-js';

function App() {
  // Your existing state (100% same)
  const [activeBroker, setActiveBroker] = useState('');
  const [brokersConnected, setBrokersConnected] = useState({ angel: false, dhan: false, mt4: false, mt5: false });
  const [pairMode, setPairMode] = useState('auto');
  const [selectedPair, setSelectedPair] = useState('');
  const [isBotActive, setIsBotActive] = useState(false);
  const [realBalance, setRealBalance] = useState('₹0');
  const [positions, setPositions] = useState([]);
  const [status, setStatus] = useState('Connect broker first...');
  const [flashMessage, setFlashMessage] = useState('');
  const [licenseValid, setLicenseValid] = useState(false);

  // NEW: In-app connection forms
  const [showForms, setShowForms] = useState({
    angel: false, dhan: false, mt4: false, mt5: false, license: false
  });
  const [creds, setCreds] = useState({
    angel: { clientCode: '', password: '', totem: '' },
    dhan: { clientId: '', accessToken: '' },
    mt4: { login: '', password: '', server: 'tcp://localhost:5555' },
    mt5: { login: '', password: '', server: 'tcp://localhost:5555' },
    license: ''
  });

  // Indian vs Forex pairs (same)
  const indianPairs = ['NIFTY', 'BANKNIFTY', 'FINNIFTY', 'RELIANCE', 'TCS', 'HDFCBANK'];
  const forexPairs = ['EURUSD', 'GBPUSD', 'USDJPY', 'AUDUSD', 'USDCAD', 'BTCUSD', 'ETHUSD', 'XAUUSD'];
  const pairs = activeBroker === 'angel' || activeBroker === 'dhan' ? indianPairs : forexPairs;

  // Secure Storage Functions
  const SECRET_KEY = 'trading-algo-app-v1';
  const storeCredentials = (broker, credentials) => {
    const encrypted = CryptoJS.AES.encrypt(JSON.stringify(credentials), SECRET_KEY).toString();
    localStorage.setItem(`cred_${broker}`, encrypted);
  };
  const getCredentials = (broker) => {
    const encrypted = localStorage.getItem(`cred_${broker}`);
    if (!encrypted) return null;
    try {
      const bytes = CryptoJS.AES.decrypt(encrypted, SECRET_KEY);
      return JSON.parse(bytes.toString(CryptoJS.enc.Utf8));
    } catch {
      return null;
    }
  };

  // Generate Device ID for License
  const generateDeviceId = () => {
    let deviceId = localStorage.getItem('deviceId');
    if (!deviceId) {
      deviceId = 'device_' + Math.random().toString(36).substr(2, 9) + Date.now();
      localStorage.setItem('deviceId', deviceId);
    }
    return deviceId;
  };

  // Flash message (same)
  useEffect(() => {
    if (flashMessage) {
      const timer = setTimeout(() => setFlashMessage(''), 4000);
      return () => clearTimeout(timer);
    }
  }, [flashMessage]);

  // Auto-load saved credentials & license
  useEffect(() => {
    const licenseKey = localStorage.getItem('licenseKey');
    if (licenseKey) {
      const deviceId = generateDeviceId();
      const licenseHash = CryptoJS.SHA256(licenseKey + deviceId).toString();
      // Simulate license validation (replace with Firebase later)
      setLicenseValid(true);
    }

    // Check saved broker connections
    ['angel', 'dhan', 'mt4', 'mt5'].forEach(broker => {
      if (getCredentials(broker)) {
        setBrokersConnected(prev => ({ ...prev, [broker]: true }));
      }
    });
  }, []);

  // SIMULATED API Connections (Replace with real APIs later)
  const simulateAngelConnect = (creds) => {
    return new Promise((resolve) => {
      setTimeout(() => {
        storeCredentials('angel', creds);
        setActiveBroker('angel');
        setBrokersConnected(prev => ({ ...prev, angel: true }));
        setRealBalance('₹85,230');
        setStatus('AngelOne Live Trading');
        resolve(true);
      }, 1500);
    });
  };

  const simulateDhanConnect = (creds) => {
    return new Promise((resolve) => {
      setTimeout(() => {
        storeCredentials('dhan', creds);
        setActiveBroker('dhan');
        setBrokersConnected(prev => ({ ...prev, dhan: true }));
        setRealBalance('₹92,450');
        setStatus('Dhan Live Trading');
        resolve(true);
      }, 1500);
    });
  };

  const simulateMtConnect = (type, creds) => {
    return new Promise((resolve) => {
      setTimeout(() => {
        storeCredentials(type, creds);
        setActiveBroker(type);
        setBrokersConnected(prev => ({ ...prev, [type]: true }));
        setRealBalance('$2,450');
        setStatus(`${type.toUpperCase()} Live Trading`);
        resolve(true);
      }, 1500);
    });
  };

  // Connection Handlers
  const handleAngelConnect = async () => {
    try {
      setFlashMessage('🔄 Connecting AngelOne...');
      await simulateAngelConnect(creds.angel);
      setFlashMessage('🟢 AngelOne Connected - LIVE');
      setShowForms(prev => ({ ...prev, angel: false }));
    } catch (error) {
      setFlashMessage('❌ AngelOne Connection Failed');
    }
  };

  const handleDhanConnect = async () => {
    try {
      setFlashMessage('🔄 Connecting Dhan...');
      await simulateDhanConnect(creds.dhan);
      setFlashMessage('🟢 Dhan Connected - LIVE');
      setShowForms(prev => ({ ...prev, dhan: false }));
    } catch (error) {
      setFlashMessage('❌ Dhan Connection Failed');
    }
  };

  const handleMtConnect = async (type) => {
    try {
      setFlashMessage(`🔄 Connecting ${type.toUpperCase()}...`);
      await simulateMtConnect(type, creds[type]);
      setFlashMessage(`🟢 ${type.toUpperCase()} Connected`);
      setShowForms(prev => ({ ...prev, [type]: false }));
    } catch (error) {
      setFlashMessage('❌ MT Connection Failed');
    }
  };

 const handleLicenseActivate = async () => {
  try {
    const deviceId = generateDeviceId();

    const response = await fetch(
      'http://localhost:5000/api/license/activate-license',
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          licenseKey: creds.license,
          deviceId
        })
      }
    );

    const data = await response.json();

    if (data.success) {
      localStorage.setItem('licenseKey', creds.license);

      setLicenseValid(true);

      setFlashMessage('✅ License Activated Successfully');

      setShowForms(prev => ({
        ...prev,
        license: false
      }));
    } else {
      setFlashMessage(`❌ ${data.message}`);
    }

  } catch (err) {
    console.error(err);

    setFlashMessage('❌ Server connection failed');
  }
};

  const startTrading = () => {
    if (!licenseValid) {
      setShowForms(prev => ({ ...prev, license: true }));
      setFlashMessage('⚠️ License Required!');
      return;
    }
    if (!activeBroker) {
      setFlashMessage('❌ Connect Broker First!');
      return;
    }

    setIsBotActive(!isBotActive);
    setStatus(`${activeBroker.toUpperCase()} ${isBotActive ? 'STOPPED' : 'LIVE TRADING'}`);

    if (!isBotActive) {
      const interval = setInterval(() => {
        const pair = pairMode === 'auto' ? pairs[Math.floor(Math.random() * pairs.length)] : selectedPair;
        setPositions(prev => [{
          id: Date.now(),
          pair,
          broker: activeBroker.toUpperCase(),
          side: Math.random() > 0.5 ? 'LONG' : 'SHORT',
          sl: '30 pips',
          tp: '60 pips',
          pnl: Math.random() > 0.7 ? '+₹1,850' : '-₹320',
          time: new Date().toLocaleTimeString(),
          strategy: 'SuperTrend + RSI (82% WR)'
        }, ...prev.slice(0, 9)]);
        setStatus(`LIVE: Executing ${pair}`);
      }, 8000);
      window.tradeInterval = interval;
    } else {
      clearInterval(window.tradeInterval);
    }
  };

  const closeTrade = (id) => {
    setPositions(prev => prev.filter(t => t.id !== id));
    setFlashMessage('Trade Closed ✅');
  };

  // Connection Forms
  const ConnectionForm = ({ type, title, fields, onConnect }) => (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-md flex items-center justify-center z-50 p-6 animate-fadeIn">
      <div className={`p-12 rounded-4xl shadow-2xl max-w-md w-full mx-4 max-h-[90vh] overflow-y-auto border-4 ${
        type === 'angel' ? 'bg-gradient-to-br from-indigo-900/90 to-purple-900/90 border-indigo-500/50 shadow-indigo-500/30' :
        type === 'dhan' ? 'bg-gradient-to-br from-emerald-900/90 to-teal-900/90 border-emerald-500/50 shadow-emerald-500/30' :
        type === 'mt4' || type === 'mt5' ? 'bg-gradient-to-br from-blue-900/90 to-cyan-900/90 border-blue-500/50 shadow-blue-500/30' :
        'bg-gradient-to-br from-purple-900/90 to-pink-900/90 border-purple-500/50 shadow-purple-500/30'
      }`}>
        <h2 className="text-4xl font-black mb-8 text-center text-white drop-shadow-2xl uppercase tracking-wide">
          {title}
        </h2>
        
        <div className="space-y-6 mb-8">
          {fields.map(field => (
            <input
              key={field.name}
              type={field.type || 'text'}
              placeholder={field.placeholder}
              value={creds[type][field.name]}
              onChange={(e) => setCreds(prev => ({
                ...prev,
                [type]: { ...prev[type], [field.name]: e.target.value }
              }))}
              className="w-full p-6 rounded-3xl bg-white/10 border-2 border-white/30 focus:border-white/60 focus:outline-none text-xl font-bold text-white placeholder-gray-400 shadow-xl backdrop-blur-xl transition-all hover:border-white/50"
            />
          ))}
        </div>
        
        <div className="flex gap-4 pt-4">
          <button
            onClick={() => setShowForms(prev => ({ ...prev, [type]: false }))}
            className="flex-1 py-6 px-8 bg-gray-700/70 hover:bg-gray-600 rounded-3xl font-bold text-xl border-2 border-gray-600 shadow-xl transition-all hover:shadow-gray-500/50 hover:scale-[1.02]"
          >
            Cancel
          </button>
          <button
            onClick={onConnect}
            className="flex-1 py-6 px-8 bg-gradient-to-r from-white to-gray-200 text-gray-900 font-black text-xl rounded-3xl shadow-2xl border-2 border-white shadow-white/30 hover:shadow-white/50 hover:scale-[1.02] transition-all duration-300"
          >
            Connect Live
          </button>
        </div>
      </div>
    </div>
  );

  // Your ORIGINAL JSX (100% preserved)
  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-900 via-gray-800 to-black text-white p-6 lg:p-12">
      {/* Flash Message */}
      {flashMessage && (
        <div className="fixed top-4 left-1/2 transform -translate-x-1/2 z-50 glass p-6 rounded-3xl shadow-2xl shadow-emerald-500/25 border-2 border-emerald-400/50 max-w-md mx-auto animate-pulse">
          <div className="text-2xl font-black text-emerald-400 text-center">{flashMessage}</div>
        </div>
      )}

      {/* License Warning */}
      {!licenseValid && (
        <div className="fixed top-20 left-1/2 transform -translate-x-1/2 z-40 bg-gradient-to-r from-orange-500/90 to-red-500/90 backdrop-blur-xl p-6 rounded-3xl shadow-2xl border-4 border-orange-400/50 max-w-2xl mx-auto animate-bounce">
          <div className="text-xl font-black text-white text-center flex items-center justify-center gap-4">
            🔑 <span>Activate License for Real Trading</span>
            <button 
              onClick={() => setShowForms(prev => ({ ...prev, license: true }))}
              className="px-8 py-3 bg-white/20 hover:bg-white/30 rounded-2xl font-bold border border-white/50 transition-all"
            >
              Activate
            </button>
          </div>
        </div>
      )}

      {/* Header (same) */}
      <div className="max-w-6xl mx-auto text-center mb-16 glass p-12 rounded-4xl backdrop-blur-xl border border-gray-700/50 shadow-2xl shadow-black/50">
        <h1 className="text-5xl lg:text-6xl font-bold text-white drop-shadow-lg mb-6">
          Welcome to JD-Algo
        </h1>
        <p className="text-2xl font-semibold text-gray-300">Live Trading Platform</p>
      </div>

      <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8 mb-16">
        {/* Brokers Panel (UPDATED BUTTONS) */}
        <div className="lg:col-span-1 space-y-6">
          <div className="glass p-8 rounded-3xl border border-gray-700/50 shadow-xl shadow-black/50 backdrop-blur-xl">
            <h3 className="text-3xl font-bold mb-8 text-center uppercase tracking-wide text-white drop-shadow-lg">Brokers</h3>
            
            <div className="space-y-4">
              <button 
                onClick={() => setShowForms(prev => ({ ...prev, angel: true }))}
                className={`w-full py-6 px-8 rounded-3xl font-bold text-xl transition-all shadow-xl border-2 border-gray-600 hover:shadow-gray-600/50 hover:scale-105 hover:border-gray-500 bg-gray-800/70 backdrop-blur-xl group ${
                  brokersConnected.angel 
                    ? 'ring-4 ring-emerald-500/40 border-emerald-400 bg-emerald-500/20 shadow-emerald-500/30 scale-102' 
                    : ''
                }`}
              >
                AngelOne {brokersConnected.angel ? '🟢 LIVE' : 'Connect'}
              </button>
              
              <button 
                onClick={() => setShowForms(prev => ({ ...prev, dhan: true }))}
                className={`w-full py-6 px-8 rounded-3xl font-bold text-xl transition-all shadow-xl border-2 border-gray-600 hover:shadow-gray-600/50 hover:scale-105 hover:border-gray-500 bg-gray-800/70 backdrop-blur-xl group ${
                  brokersConnected.dhan 
                    ? 'ring-4 ring-emerald-500/40 border-emerald-400 bg-emerald-500/20 shadow-emerald-500/30 scale-102' 
                    : ''
                }`}
              >
                Dhan {brokersConnected.dhan ? '🟢 LIVE' : 'Connect'}
              </button>
              
              <button 
                onClick={() => setShowForms(prev => ({ ...prev, mt4: true }))}
                className={`w-full py-6 px-8 rounded-3xl font-bold text-xl transition-all shadow-xl border-2 border-gray-600 hover:shadow-gray-600/50 hover:scale-105 hover:border-gray-500 bg-gray-800/70 backdrop-blur-xl group ${
                  brokersConnected.mt4 
                    ? 'ring-4 ring-emerald-500/40 border-emerald-400 bg-emerald-500/20 shadow-emerald-500/30 scale-102' 
                    : ''
                }`}
              >
                MT4 {brokersConnected.mt4 ? '🟢 LIVE' : 'Connect'}
              </button>
              
              <button 
                onClick={() => setShowForms(prev => ({ ...prev, mt5: true }))}
                className={`w-full py-6 px-8 rounded-3xl font-bold text-xl transition-all shadow-xl border-2 border-gray-600 hover:shadow-gray-600/50 hover:scale-105 hover:border-gray-500 bg-gray-800/70 backdrop-blur-xl group ${
                  brokersConnected.mt5 
                    ? 'ring-4 ring-emerald-500/40 border-emerald-400 bg-emerald-500/20 shadow-emerald-500/30 scale-102' 
                    : ''
                }`}
              >
                MT5 {brokersConnected.mt5 ? '🟢 LIVE' : 'Connect'}
              </button>
            </div>
          </div>

          {activeBroker && licenseValid && (
            <div className="glass p-8 rounded-3xl border-4 border-emerald-400/30 bg-emerald-500/5 shadow-2xl shadow-emerald-500/20 text-center">
              <div className="text-3xl font-black text-emerald-400 mb-4 drop-shadow-lg">{activeBroker.toUpperCase()}</div>
              <div className="text-xl font-bold text-emerald-300">ACTIVE BROKER</div>
            </div>
          )}
        </div>

        {/* Rest of your UI stays EXACTLY SAME */}
        {/* Main Panel, Stats, Trading Button, Positions - ALL PRESERVED */}
        <div className="lg:col-span-2 glass p-12 rounded-4xl border border-gray-700/50 shadow-2xl shadow-black/50 backdrop-blur-xl">
          {/* Your existing main panel code here - copy from your original */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 mb-12">
            <div className="text-center p-10 rounded-3xl bg-gray-800/50 border border-gray-600/50 shadow-xl shadow-black/30 backdrop-blur-xl">
              <div className="text-4xl lg:text-5xl font-black text-emerald-400 mb-6 drop-shadow-lg">{realBalance}</div>
              <div className="text-xl font-bold text-gray-300">Real Balance</div>
            </div>
            
            <div className="p-10 rounded-3xl bg-gray-800/50 border border-gray-600/50 shadow-xl shadow-black/30 backdrop-blur-xl">
              
                           <div className="text-xl font-bold mb-6 text-center text-gray-300">Pair Selection</div>
              <div className="flex gap-4 mb-6">
                <button 
                  onClick={() => setPairMode('auto')}
                  className={`flex-1 py-4 px-6 rounded-2xl font-bold transition-all border-2 border-gray-600 hover:border-gray-500 hover:shadow-gray-600/50 hover:scale-105 bg-gray-900/70 backdrop-blur-xl ${pairMode === 'auto' ? 'border-emerald-400 bg-emerald-500/20 shadow-emerald-400/30 scale-102 ring-2 ring-emerald-400/50' : ''}`}
                >
                  Auto ({pairs.length} pairs)
                </button>
                <button 
                  onClick={() => setPairMode('manual')}
                  className={`flex-1 py-4 px-6 rounded-2xl font-bold transition-all border-2 border-gray-600 hover:border-gray-500 hover:shadow-gray-600/50 hover:scale-105 bg-gray-900/70 backdrop-blur-xl ${pairMode === 'manual' ? 'border-emerald-400 bg-emerald-500/20 shadow-emerald-400/30 scale-102 ring-2 ring-emerald-400/50' : ''}`}
                >
                  Manual
                </button>
              </div>
              
              {pairMode === 'manual' && (
                <select 
                  value={selectedPair}
                  onChange={e => setSelectedPair(e.target.value)}
                  className="w-full p-4 rounded-2xl bg-gray-900/70 border-2 border-gray-600 focus:border-emerald-400 focus:outline-none text-xl font-bold shadow-lg backdrop-blur-xl"
                >
                  {pairs.map(pair => (
                    <option key={pair} value={pair}>{pair}</option>
                  ))}
                </select>
              )}
            </div>
            
            <div className="p-10 rounded-3xl bg-gray-800/50 border border-gray-600/50 shadow-xl shadow-black/30 text-center backdrop-blur-xl col-span-1 md:col-span-2 lg:col-span-1">
              <div className="text-3xl font-black text-yellow-400 mb-6 drop-shadow-lg">{status}</div>
              <div className="text-xl font-bold text-gray-300">Dark Professional Trading</div>
            </div>
          </div>

          <div className="text-center">
            <button 
              onClick={startTrading}
              disabled={!activeBroker || !licenseValid}
              className={`px-20 py-12 lg:px-32 lg:py-16 rounded-4xl font-black text-2xl lg:text-3xl uppercase tracking-wider shadow-2xl mx-auto block transition-all duration-300 border-4 ${
                isBotActive
                  ? 'bg-emerald-600 border-emerald-400 shadow-emerald-500/60 hover:shadow-emerald-500/80 scale-105 ring-8 ring-emerald-500/30 animate-pulse'
                  : (!activeBroker || !licenseValid
                      ? 'bg-gray-700/50 border-gray-600/50 cursor-not-allowed opacity-60' 
                      : 'bg-gradient-to-r from-gray-700 to-gray-600 border-gray-500 hover:from-gray-600 hover:to-gray-500 hover:shadow-gray-500/60 hover:scale-105 hover:border-gray-400 shadow-gray-700/50'
                    )
              }`}
            >
              {isBotActive ? '🟢 Live Trading Active' : licenseValid ? 'Start Real Trading' : 'Activate License'}
            </button>
          </div>
        </div>
      </div>

      {/* Positions (same) */}
      <div className="max-w-6xl mx-auto mb-24">
        <div className="glass p-12 lg:p-16 rounded-4xl border border-gray-700/50 shadow-2xl shadow-black/50 backdrop-blur-xl">
          <h3 className="text-4xl lg:text-5xl font-bold mb-16 text-center text-white drop-shadow-2xl">
            Live Positions
          </h3>
          
          {positions.length === 0 ? (
            <div className="text-center py-32 rounded-3xl bg-gray-900/50 border border-gray-700/50 shadow-xl shadow-black/30">
              <div className="text-5xl text-gray-500 mb-8 drop-shadow-lg">No Active Trades</div>
              <div className="text-2xl text-gray-400 font-semibold">
                {licenseValid ? 'Connect broker and start trading' : 'Activate license first'}
              </div>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
              {positions.map(pos => (
                <div key={pos.id} className="glass p-8 lg:p-10 rounded-3xl border border-gray-700/50 shadow-xl shadow-black/30 hover:shadow-gray-600/50 hover:scale-105 transition-all duration-300 backdrop-blur-xl group cursor-pointer">
                  <div className="flex justify-between items-start mb-8 pb-8 border-b border-gray-700/50">
                    <div>
                      <div className="text-3xl lg:text-4xl font-black text-white drop-shadow-lg mb-3">{pos.pair}</div>
                      <div className="px-6 py-3 rounded-xl inline-block bg-emerald-500/20 border border-emerald-400/50 text-emerald-300 font-bold text-lg shadow-emerald-400/30">
                        {pos.broker}
                      </div>
                    </div>
                    <button 
                      onClick={() => closeTrade(pos.id)}
                      className="opacity-0 group-hover:opacity-100 p-4 bg-red-500/70 hover:bg-red-600 rounded-3xl transition-all shadow-xl ml-4 font-bold text-xl shadow-red-500/40 hover:shadow-red-500/60 hover:scale-110"
                    >
                      ✕
                    </button>
                  </div>
                  
                  <div className="space-y-6">
                    <div className="text-4xl font-black text-emerald-400 drop-shadow-lg text-center py-4 bg-emerald-500/10 rounded-2xl border border-emerald-400/30">
                      {pos.side}
                    </div>
                    <div className="grid grid-cols-2 gap-6 text-xl">
                      <div className="flex justify-between p-4 bg-gray-800/50 rounded-2xl border border-gray-700/50">
                        <span className="font-bold text-gray-400">SL:</span>
                        <span className="font-mono text-green-400 font-bold">{pos.sl}</span>
                      </div>
                      <div className="flex justify-between p-4 bg-gray-800/50 rounded-2xl border border-gray-700/50">
                        <span className="font-bold text-gray-400">TP:</span>
                        <span className="font-mono text-blue-400 font-bold">{pos.tp}</span>
                      </div>
                    </div>
                    <div className={`text-3xl font-black py-6 px-8 rounded-3xl text-center shadow-2xl border-4 ${
                      pos.pnl.includes('+') 
                        ? 'bg-emerald-500/20 border-emerald-400 shadow-emerald-400/40 text-emerald-400' 
                        : 'bg-red-500/20 border-red-400 shadow-red-400/40 text-red-400'
                    }`}>
                      {pos.pnl}
                    </div>
                    <div className="text-lg opacity-80 font-mono text-center">{pos.strategy}</div>
                    <div className="text-xl opacity-80 font-mono text-center">{pos.time}</div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Footer (same) */}
      <footer className="max-w-6xl mx-auto p-12 rounded-4xl glass text-center border border-gray-700/50 shadow-2xl shadow-black/50 backdrop-blur-xl">
        <div className="text-3xl lg:text-4xl font-bold text-white drop-shadow-lg mb-6">
          Powered by Xyca Technologies Private Ltd.
        </div>
        <p className="text-xl text-gray-400 font-semibold">Professional Trading Platform</p>
      </footer>

      {/* ALL Connection Forms */}
      {showForms.angel && (
        <ConnectionForm
          type="angel"
          title="AngelOne SmartAPI"
          fields={[
            { name: 'clientCode', placeholder: 'Client Code', type: 'text' },
            { name: 'password', placeholder: 'Password', type: 'password' },
            { name: 'totem', placeholder: 'TOTP (optional)' }
          ]}
          onConnect={handleAngelConnect}
        />
      )}

      {showForms.dhan && (
        <ConnectionForm
          type="dhan"
          title="Dhan HQ"
          fields={[
            { name: 'clientId', placeholder: 'Client ID', type: 'text' },
            { name: 'accessToken', placeholder: 'Access Token', type: 'password' }
          ]}
          onConnect={handleDhanConnect}
        />
      )}

      {showForms.mt4 && (
        <ConnectionForm
          type="mt4"
          title="MetaTrader 4"
          fields={[
            { name: 'login', placeholder: 'Login (numbers)', type: 'text' },
            { name: 'password', placeholder: 'Password', type: 'password' },
            { name: 'server', placeholder: 'Server (tcp://ip:5555)' }
          ]}
          onConnect={() => handleMtConnect('mt4')}
        />
      )}

      {showForms.mt5 && (
        <ConnectionForm
          type="mt5"
          title="MetaTrader 5"
          fields={[
            { name: 'login', placeholder: 'Login (numbers)', type: 'text' },
            { name: 'password', placeholder: 'Password', type: 'password' },
            { name: 'server', placeholder: 'Server (tcp://ip:5555)' }
          ]}
          onConnect={() => handleMtConnect('mt5')}
        />
      )}

      {showForms.license && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md flex items-center justify-center z-50 p-6">
          <div className="bg-gradient-to-br from-purple-900/95 to-pink-900/95 p-12 rounded-4xl border-4 border-purple-500/50 shadow-2xl max-w-md w-full mx-4">
            <h2 className="text-4xl font-black text-purple-300 mb-8 text-center drop-shadow-2xl">Device License</h2>
            <div className="text-center mb-6 p-6 bg-black/30 rounded-3xl border border-white/20">
              <div className="text-sm text-gray-400 mb-2">Device ID:</div>
              <div className="font-mono font-bold text-white text-lg">{generateDeviceId()}</div>
            </div>
            <input
              type="text"
              placeholder="Enter License Key"
              value={creds.license}
              onChange={(e) => setCreds(prev => ({ ...prev, license: e.target.value }))}
              className="w-full p-6 rounded-3xl bg-white/10 border-2 border-purple-400/50 focus:border-purple-400 text-xl font-bold text-white placeholder-gray-400 shadow-xl mb-8"
            />
            <div className="flex gap-4">
              <button
                onClick={() => setShowForms(prev => ({ ...prev, license: false }))}
                className="flex-1 py-6 bg-gray-700/70 hover:bg-gray-600 rounded-3xl font-bold text-xl"
              >
                Cancel
              </button>
              <button
                onClick={handleLicenseActivate}
                className="flex-1 py-6 bg-gradient-to-r from-purple-600 to-pink-600 hover:from-purple-700 hover:to-pink-700 rounded-3xl font-bold text-xl shadow-2xl shadow-purple-500/50"
              >
                Activate
              </button>
            </div>
          </div>
        </div>
      )}

      <style jsx>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: scale(0.95); }
          to { opacity: 1; transform: scale(1); }
        }
        .animate-fadeIn {
          animation: fadeIn 0.3s ease-out;
        }
        .glass {
          background: rgba(255, 255, 255, 0.05);
          backdrop-filter: blur(20px);
          border: 1px solid rgba(255, 255, 255, 0.1);
        }
      `}</style>
    </div>
  );
}

export default App;
